package main

import (
	"fmt"
	"log"
	"net/http"

	"github.com/gorilla/mux"
	"text/template"
)

type Comment struct {
	Name  string
	Text  string
	Email string
}

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	vars := mux.Vars(r)
	id := vars["id"]

	comments := []Comment{
		{"John Doe", "This is a comment.", "john@example.com"},
		{"Jane Doe", "This is another comment with <b>bold</b> and <i>italic</i> text.", "jane@example.com"},
	}

	tmpl, err := template.ParseFiles("comments.html")
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	err = tmpl.ExecuteTemplate(w, "comments.html", map[string]interface{}{
		"Title":   fmt.Sprintf("Comments for %s", id),
		"Comments": comments,
	})
	if err != nil {
		log.Println(err)
		http.Error(w, err.Error(), http.StatusInternalServerError)
	}
}

func main() {
	r := mux.NewRouter()
	r.HandleFunc("/comments/{id}", commentsHandler).Methods("GET")

	http.ListenAndServe(":8080", r)
}